fixed_code:
fn main() {
    let data = vec![10, 20, 30, 40];

    for page in 0..2 {
        let start = page * 2;
        let end = std::cmp::min(start + 2, data.len());
        println!("Page {}: {:?}", page, &data[start..end]);
    }
}
